const char*   int_to_str (int64_t   n) {
    if ((n  ==  0)) {
        return "0";
    }
    int64_t   x = n;
    bool   neg = false;
    if ((x  <  0)) {
        (neg  =  true);
        (x  =  (-x));
    }
    const char*   s = "";
    while ((x  >  0)) {
        int   d = (( int )(x  %  10));
        const char*   ch = ((const char*(*)(int))digit_str)(d);
        (s  =  __glide_string_concat(ch, s));
        (x  =  (x  /  10));
    }
    if (neg) {
        (s  =  __glide_string_concat("-", s));
    }
    return s;
}

const char*   digit_str (int   d) {
    if ((d  ==  0)) {
        return "0";
    }
    if ((d  ==  1)) {
        return "1";
    }
    if ((d  ==  2)) {
        return "2";
    }
    if ((d  ==  3)) {
        return "3";
    }
    if ((d  ==  4)) {
        return "4";
    }
    if ((d  ==  5)) {
        return "5";
    }
    if ((d  ==  6)) {
        return "6";
    }
    if ((d  ==  7)) {
        return "7";
    }
    if ((d  ==  8)) {
        return "8";
    }
    return "9";
}

