const char*   op_to_c (int   op) {
    if ((op  ==  OP_ADD)) {
        return "+";
    }
    if ((op  ==  OP_SUB)) {
        return "-";
    }
    if ((op  ==  OP_MUL)) {
        return "*";
    }
    if ((op  ==  OP_DIV)) {
        return "/";
    }
    if ((op  ==  OP_MOD)) {
        return "%";
    }
    if ((op  ==  OP_EQ)) {
        return "==";
    }
    if ((op  ==  OP_NE)) {
        return "!=";
    }
    if ((op  ==  OP_LT)) {
        return "<";
    }
    if ((op  ==  OP_LE)) {
        return "<=";
    }
    if ((op  ==  OP_GT)) {
        return ">";
    }
    if ((op  ==  OP_GE)) {
        return ">=";
    }
    if ((op  ==  OP_AND)) {
        return "&&";
    }
    if ((op  ==  OP_OR)) {
        return "||";
    }
    if ((op  ==  OP_BIT_AND)) {
        return "&";
    }
    if ((op  ==  OP_BIT_OR)) {
        return "|";
    }
    if ((op  ==  OP_BIT_XOR)) {
        return "^";
    }
    if ((op  ==  OP_SHL)) {
        return "<<";
    }
    if ((op  ==  OP_SHR)) {
        return ">>";
    }
    if ((op  ==  OP_ASSIGN)) {
        return "=";
    }
    if ((op  ==  OP_PLUS_ASSIGN)) {
        return "+=";
    }
    if ((op  ==  OP_MINUS_ASSIGN)) {
        return "-=";
    }
    if ((op  ==  OP_STAR_ASSIGN)) {
        return "*=";
    }
    if ((op  ==  OP_SLASH_ASSIGN)) {
        return "/=";
    }
    return "?";
}

const char*   unop_to_c (int   op) {
    if ((op  ==  UN_NEG)) {
        return "-";
    }
    if ((op  ==  UN_NOT)) {
        return "!";
    }
    if ((op  ==  UN_BIT_NOT)) {
        return "~";
    }
    if ((op  ==  UN_DEREF)) {
        return "*";
    }
    if ((op  ==  UN_ADDR)) {
        return "&";
    }
    if ((op  ==  UN_ADDR_MUT)) {
        return "&";
    }
    return "?";
}

